import{_ as a,o as s,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"development/architecture.md","filePath":"development/architecture.md"}'),t={name:"development/architecture.md"};function o(i,e,l,c,d,p){return s(),n("div",null,[...e[0]||(e[0]=[r(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>R3 is a modular, async game server administration bot written in Rust. This page describes the internal architecture and data flow.</p><h2 id="high-level-overview" tabindex="-1">High-Level Overview <a class="header-anchor" href="#high-level-overview" aria-label="Permalink to &quot;High-Level Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────┐     ┌──────────┐     ┌──────────────┐</span></span>
<span class="line"><span>│ Game Server  │────▶│ Log File │────▶│  Log Tailer  │</span></span>
<span class="line"><span>│ (Urban Terror│     └──────────┘     └──────┬───────┘</span></span>
<span class="line"><span>│  4.3)        │                             │ raw lines</span></span>
<span class="line"><span>│              │◀────┐                       ▼</span></span>
<span class="line"><span>└─────────────┘     │               ┌──────────────┐</span></span>
<span class="line"><span>                    │               │    Parser     │</span></span>
<span class="line"><span>                    │               │ (UrbanTerror) │</span></span>
<span class="line"><span>                    │               └──────┬───────┘</span></span>
<span class="line"><span>                    │                      │ events</span></span>
<span class="line"><span>                    │                      ▼</span></span>
<span class="line"><span>              ┌─────┴────┐         ┌──────────────┐</span></span>
<span class="line"><span>              │   RCON    │◀───────│   Plugins    │</span></span>
<span class="line"><span>              │  Client   │        │  (30 total)  │</span></span>
<span class="line"><span>              └──────────┘         └──────┬───────┘</span></span>
<span class="line"><span>                                          │</span></span>
<span class="line"><span>                                          ▼</span></span>
<span class="line"><span>                                   ┌──────────────┐</span></span>
<span class="line"><span>                                   │   Storage    │</span></span>
<span class="line"><span>                                   │ SQLite/MySQL │</span></span>
<span class="line"><span>                                   └──────────────┘</span></span></code></pre></div><h2 id="module-structure" tabindex="-1">Module Structure <a class="header-anchor" href="#module-structure" aria-label="Permalink to &quot;Module Structure&quot;">​</a></h2><h3 id="src-main-rs" tabindex="-1"><code>src/main.rs</code> <a class="header-anchor" href="#src-main-rs" aria-label="Permalink to &quot;\`src/main.rs\`&quot;">​</a></h3><p>Entry point. Loads config, initializes storage, registers all plugins, starts the log tailer, and optionally starts the web server.</p><h3 id="src-config" tabindex="-1"><code>src/config/</code> <a class="header-anchor" href="#src-config" aria-label="Permalink to &quot;\`src/config/\`&quot;">​</a></h3><p>TOML configuration parsing with serde. Defines all config structs (<code>Config</code>, <code>ServerConfig</code>, <code>WebConfig</code>, <code>PluginConfig</code>).</p><h3 id="src-core" tabindex="-1"><code>src/core/</code> <a class="header-anchor" href="#src-core" aria-label="Permalink to &quot;\`src/core/\`&quot;">​</a></h3><p>The bot&#39;s runtime core:</p><ul><li><strong><code>client.rs</code></strong> — Single connected player state (name, GUID, IP, group, score, team, etc.)</li><li><strong><code>clients.rs</code></strong> — Thread-safe client manager (<code>Arc&lt;RwLock&lt;HashMap&gt;&gt;</code>)</li><li><strong><code>context.rs</code></strong> — Shared bot context passed to plugins: clients, storage, config, RCON sender</li><li><strong><code>game.rs</code></strong> — Current game state (map, game type, scores)</li><li><strong><code>log_tailer.rs</code></strong> — Async file tailer with inotify/polling and log rotation detection</li><li><strong><code>types.rs</code></strong> — Shared type definitions (groups, penalties, stats records, etc.)</li></ul><h3 id="src-events" tabindex="-1"><code>src/events/</code> <a class="header-anchor" href="#src-events" aria-label="Permalink to &quot;\`src/events/\`&quot;">​</a></h3><p>Event type definitions. Over 60 event variants covering kills, chat, connections, game state changes, admin actions, and more.</p><h3 id="src-parsers" tabindex="-1"><code>src/parsers/</code> <a class="header-anchor" href="#src-parsers" aria-label="Permalink to &quot;\`src/parsers/\`&quot;">​</a></h3><p>Log line parsing:</p><ul><li><strong><code>traits.rs</code></strong> — <code>Parser</code> trait definition</li><li><strong><code>urbanterror/mod.rs</code></strong> — Urban Terror 4.3 parser with 18 regex patterns and 40+ weapon mappings</li></ul><h3 id="src-plugins" tabindex="-1"><code>src/plugins/</code> <a class="header-anchor" href="#src-plugins" aria-label="Permalink to &quot;\`src/plugins/\`&quot;">​</a></h3><p>Plugin system:</p><ul><li><strong><code>traits.rs</code></strong> — <code>Plugin</code> trait (name, enable/disable, handle_event, settings, commands)</li><li><strong><code>registry.rs</code></strong> — Plugin registry for ordering and dispatching events</li><li><strong><code>mod.rs</code></strong> — Re-exports all 30 plugins</li></ul><p>Each plugin lives in its own subdirectory (e.g., <code>plugins/admin/mod.rs</code>).</p><h3 id="src-rcon" tabindex="-1"><code>src/rcon/</code> <a class="header-anchor" href="#src-rcon" aria-label="Permalink to &quot;\`src/rcon/\`&quot;">​</a></h3><p>UDP RCON client for the Quake 3 engine protocol. Sends commands to the game server and parses responses. Supports the <code>\\xff\\xff\\xff\\xff</code> packet prefix.</p><h3 id="src-storage" tabindex="-1"><code>src/storage/</code> <a class="header-anchor" href="#src-storage" aria-label="Permalink to &quot;\`src/storage/\`&quot;">​</a></h3><p>Database abstraction:</p><ul><li><strong><code>mod.rs</code></strong> — <code>Storage</code> trait with all database operations</li><li><strong><code>sqlite.rs</code></strong> — SQLite backend (via <code>sqlx</code>)</li><li><strong><code>mysql.rs</code></strong> — MySQL backend (via <code>sqlx</code>)</li></ul><p>Both backends support automatic migrations from the <code>migrations/</code> directory.</p><h3 id="src-web" tabindex="-1"><code>src/web/</code> <a class="header-anchor" href="#src-web" aria-label="Permalink to &quot;\`src/web/\`&quot;">​</a></h3><p>Web dashboard and API:</p><ul><li><strong><code>mod.rs</code></strong> — Axum router setup, static file serving via <code>rust_embed</code></li><li><strong><code>auth.rs</code></strong> — JWT authentication middleware and extractors</li><li><strong><code>state.rs</code></strong> — Shared application state for web handlers</li><li><strong><code>ws.rs</code></strong> — WebSocket handler for real-time events</li><li><strong><code>api/</code></strong> — REST API endpoint handlers (13 modules)</li></ul><h2 id="event-flow" tabindex="-1">Event Flow <a class="header-anchor" href="#event-flow" aria-label="Permalink to &quot;Event Flow&quot;">​</a></h2><ol><li><strong>Game server</strong> writes log lines to the game log file</li><li><strong>Log Tailer</strong> reads new lines asynchronously (with rotation handling)</li><li><strong>Parser</strong> converts raw log lines into typed <code>Event</code> values</li><li><strong>Event Dispatcher</strong> sends each event to all enabled plugins in priority order</li><li><strong>Plugins</strong> process events and may: <ul><li>Send RCON commands to the game server</li><li>Read/write to the database</li><li>Broadcast WebSocket messages to the dashboard</li></ul></li><li><strong>Web Dashboard</strong> receives real-time updates and serves the admin UI</li></ol><h2 id="async-runtime" tabindex="-1">Async Runtime <a class="header-anchor" href="#async-runtime" aria-label="Permalink to &quot;Async Runtime&quot;">​</a></h2><p>R3 uses <code>tokio</code> as its async runtime. Key async operations:</p><ul><li>File I/O (log tailing)</li><li>UDP socket (RCON)</li><li>Database queries (sqlx)</li><li>HTTP server (axum)</li><li>WebSocket connections</li></ul><h2 id="plugin-lifecycle" tabindex="-1">Plugin Lifecycle <a class="header-anchor" href="#plugin-lifecycle" aria-label="Permalink to &quot;Plugin Lifecycle&quot;">​</a></h2><ol><li><strong>Construction</strong> — Plugin is created with its config settings</li><li><strong>Enable</strong> — <code>on_enable()</code> called, plugin initializes its state</li><li><strong>Event Handling</strong> — <code>handle_event()</code> called for each game event</li><li><strong>Disable</strong> — <code>on_disable()</code> called during shutdown</li></ol>`,37)])])}const u=a(t,[["render",o]]);export{h as __pageData,u as default};
